arguments.new_str:
using Microsoft.ML;
using Microsoft.ML.Data;
using Microsoft.Extensions.ML;

var builder = WebApplication.CreateBuilder(args);

// Train the model at startup and save it
var modelPath = Path.Combine(builder.Environment.ContentRootPath, "Data", "ChurnModel.zip");
TrainModel(
    Path.Combine(builder.Environment.ContentRootPath, "Data", "customers.csv"),
    modelPath);

// Register the pooled prediction engine (thread-safe)
builder.Services.AddPredictionEnginePool<CustomerInput, ChurnPrediction>()
    .FromFile(modelPath);

var app = builder.Build();

app.MapGet("/", () => "Churn Predictor API — POST /predict with { age, income, region, purchaseHistory }");

app.MapPost("/predict", (CustomerInput input, PredictionEnginePool<CustomerInput, ChurnPrediction> pool) =>
{
    var prediction = pool.Predict(input);
    return Results.Ok(new
    {
        willChurn = prediction.PredictedLabel,
        probability = prediction.Probability,
        score = prediction.Score
    });
});

app.Run();

static void TrainModel(string dataPath, string modelPath)
{
    var mlContext = new MLContext(seed: 42);

    var data = mlContext.Data.LoadFromTextFile<CustomerData>(
        dataPath, separatorChar: ',', hasHeader: true);

    var split = mlContext.Data.TrainTestSplit(data, testFraction: 0.2, seed: 42);

    var pipeline = mlContext.Transforms.Categorical.OneHotEncoding("RegionEncoded", nameof(CustomerData.Region))
        .Append(mlContext.Transforms.Concatenate("Features",
            nameof(CustomerData.Age),
            nameof(CustomerData.Income),
            "RegionEncoded",
            nameof(CustomerData.PurchaseHistory)))
        .Append(mlContext.Transforms.NormalizeMinMax("Features"))
        .Append(mlContext.BinaryClassification.Trainers.SdcaLogisticRegression(
            labelColumnName: "Label", featureColumnName: "Features"));

    // Map "Yes"/"No" to boolean label before training
    var fullPipeline = mlContext.Transforms.CustomMapping<CustomerData, LabelMapping>(
            (input, output) => output.Label = string.Equals(input.Churned, "Yes", StringComparison.OrdinalIgnoreCase),
            contractName: "ChurnLabelMapping")
        .Append(pipeline);

    var model = fullPipeline.Fit(split.TrainSet);

    // Evaluate on the test set
    var predictions = model.Transform(split.TestSet);
    var metrics = mlContext.BinaryClassification.Evaluate(predictions, labelColumnName: "Label");
    Console.WriteLine($"Model trained — AUC: {metrics.AreaUnderRocCurve:F4}, Accuracy: {metrics.Accuracy:F4}, F1: {metrics.F1Score:F4}");

    mlContext.Model.Save(model, data.Schema, modelPath);
    Console.WriteLine($"Model saved to {modelPath}");
}

// --- Data classes ---

public class CustomerData
{
    [LoadColumn(0)] public float Age { get; set; }
    [LoadColumn(1)] public float Income { get; set; }
    [LoadColumn(2)] public string Region { get; set; } = "";
    [LoadColumn(3)] public float PurchaseHistory { get; set; }
    [LoadColumn(4)] public string Churned { get; set; } = "";
}

public class LabelMapping
{
    public bool Label { get; set; }
}

public class CustomerInput
{
    public float Age { get; set; }
    public float Income { get; set; }
    public string Region { get; set; } = "";
    public float PurchaseHistory { get; set; }
}

public class ChurnPrediction
{
    [ColumnName("PredictedLabel")]
    public bool PredictedLabel { get; set; }
    public float Probability { get; set; }
    public float Score { get; set; }
}

